#include <stdio.h>
#include <stdbool.h>

bool subsetSumUtil(int ind, int target, int arr[], int dp[][10001]) {
    if (target == 0) return true;
    if (ind == 0) return arr[0] == target;
    if (dp[ind][target] != -1) return dp[ind][target];
    bool notTaken = subsetSumUtil(ind - 1, target, arr, dp);
    bool taken = false;
    if (arr[ind] <= target) taken = subsetSumUtil(ind - 1, target - arr[ind], arr, dp);
    dp[ind][target] = notTaken || taken;
    return dp[ind][target];
}

bool subsetSumToK(int n, int k, int arr[]) {
    int dp[n][10001];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= k; j++) {
            dp[i][j] = -1;
        }
    }
    return subsetSumUtil(n - 1, k, arr, dp);
}

int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int k;
    scanf("%d", &k);
    if (subsetSumToK(n, k, arr)) printf("true");
    else printf("false");
    return 0;
}

